import fs from "node:fs";
import path from "node:path";

const sourcePath = path.resolve("prisma/schema.prisma");
const targetPath = path.resolve("prisma/schema.postgres.prisma");

const source = fs.readFileSync(sourcePath, "utf8");

if (!source.includes('provider = "sqlite"')) {
  throw new Error('Expected prisma/schema.prisma to contain datasource provider = "sqlite".');
}

const converted = source.replace('provider = "sqlite"', 'provider = "postgresql"');
const header = [
  "// Auto-generated from prisma/schema.prisma.",
  "// Do not edit this file directly.",
  "// Run: npm run prisma:sync:postgres",
  "",
].join("\n");

fs.writeFileSync(targetPath, `${header}${converted}`);
console.log(`PostgreSQL schema synced to ${targetPath}`);
